   // ... other imports and interfaces ...

   export class KeyboardManager {
     // ... constructor and private members ...

     private registerDefaults(cb: ActionCallbacks): void {
       this.registry.register({
         id: 'next-tab',
         label: 'Next Tab',
         identifier: 'BracketRight', // Use code for physical key
         isCodeBased: true,
         modifiers: ['Meta', 'Shift'],
         action: cb.onNextTab,
       });

       this.registry.register({
         id: 'prev-tab',
         label: 'Previous Tab',
         identifier: 'BracketLeft', // Use code for physical key
         isCodeBased: true,
         modifiers: ['Meta', 'Shift'],
         action: cb.onPrevTab,
       });

       this.registry.register({
         id: 'find',
         label: 'Find',
         identifier: 'f', // Use key character, assuming consistency
         isCodeBased: false,
         modifiers: ['Meta'],
         action: cb.onFind,
       });

       this.registry.register({
         id: 'save',
         label: 'Save',
         identifier: 's', // Use key character, assuming consistency
         isCodeBased: false,
         modifiers: ['Meta'],
         action: cb.onSave,
       });
     }
     // ... rest of the class ...
   }
   ```

**3. Modify `ShortcutHandler.ts`:**
   - Update the `dispatch` method to pass the full `KeyEvent` to `this.registry.lookup`, as the lookup logic now handles differentiating between `code` and `key`.

   ```typescript
   // src/shortcuts/ShortcutHandler.ts
   // ... other imports and interfaces ...

   export class ShortcutHandler {
     // ... constructor and private members ...

     dispatch(event: KeyEvent): DispatchResult {
       const modifiers: Array<'Ctrl' | 'Shift' | 'Alt' | 'Meta'> = [];
       if (event.ctrlKey) modifiers.push('Ctrl');
       if (event.shiftKey) modifiers.push('Shift');
       if (event.altKey) modifiers.push('Alt');
       if (event.metaKey) modifiers.push('Meta');

       // Pass the full event to lookup, allowing it to decide between code/key matching
       const match = this.registry.lookup(event, modifiers);

       const result: DispatchResult = {
         matched: !!match,
         shortcutId: match?.id,
         receivedKey: event.key,
         receivedCode: event.code,
       };

       this.dispatchLog.push(result);

       if (match) {
         match.action();
       }

       return result;
     }

     // ... rest of the class ...
   }
   ```

This architectural change ensures that shortcuts tied to physical key positions will function correctly across all keyboard layouts, making the system significantly more robust and user-friendly for an international audience. The `isCodeBased` flag and differentiated normalization in `ShortcutRegistry` allow flexibility for both physical-key and character-based shortcuts within a unified system.
